import {
  ChangeDetectionStrategy,
  Component,
  computed,
  signal,
} from '@angular/core';
import { IngestionJob } from '../core/models';

@Component({
  selector: 'app-admin-jobs',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  templateUrl: './admin-jobs.component.html',
  styleUrl: './admin-jobs.component.css',
})
export class AdminJobsComponent {
  /**
   * DATA CONTRACT: backend-provided ingestion job history. Declared as a typed
   * signal of mock objects so mockup_cleaner/service_agent can wire it to the
   * ingestion job API.
   */
  readonly jobs = signal<IngestionJob[]>([]);

  readonly successCount = computed(
    () => this.jobs().filter((j) => j.status === 'success').length,
  );
  readonly failedCount = computed(
    () => this.jobs().filter((j) => j.status === 'failed').length,
  );
  readonly activeCount = computed(
    () =>
      this.jobs().filter(
        (j) => j.status === 'running' || j.status === 'retrying',
      ).length,
  );

  formatDuration(ms: number | null): string {
    if (ms === null) return '—';
    const s = Math.round(ms / 1000);
    const m = Math.floor(s / 60);
    return m > 0 ? `${m}m ${s % 60}s` : `${s}s`;
  }

  formatTime(iso: string): string {
    return new Date(iso).toLocaleString('en-US', {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  }
}
